import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getAllSupportsApi, getMySupportsApi, updateSupportStatusApi } from '../api/apiServices';

const RequestList = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('ALL'); // 'ALL', 'MINE', 'OTHERS'
  const [statusFilter, setStatusFilter] = useState('ALL');
  const [requests, setRequests] = useState([]);
  const [myRequests, setMyRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedReq, setSelectedReq] = useState(null);

  const currentUser = JSON.parse(localStorage.getItem('user') || '{}');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [allRes, myRes] = await Promise.all([
        getAllSupportsApi().catch(() => ({ data: [] })),
        getMySupportsApi().catch(() => ({ data: [] }))
      ]);
      setRequests(allRes.data || []);
      setMyRequests(myRes.data || []);
    } catch (e) {
      console.error(e);
    }
    setLoading(false);
  };

  const getFilteredRequests = () => {
    let list = [];
    if (activeTab === 'ALL') {
      list = requests;
    } else if (activeTab === 'MINE') {
      list = myRequests;
    } else if (activeTab === 'OTHERS') {
      const myIds = new Set(myRequests.map(r => r.id));
      list = requests.filter(r => !myIds.has(r.id));
    }

    if (statusFilter !== 'ALL') {
      list = list.filter(r => r.status === statusFilter);
    }

    // Sort logic (newest first)
    list.sort((a,b) => new Date(b.createdAt) - new Date(a.createdAt));
    return list;
  };

  const filtered = getFilteredRequests();

  const handleUpdateStatus = async (id, newStatus) => {
    try {
      await updateSupportStatusApi(id, newStatus);
      fetchData();
      setSelectedReq(null);
    } catch (e) {
      alert('Cập nhật thất bại. Vui lòng kiểm tra quyền!');
    }
  };

  const handleOpenMap = (req) => {
    navigate('/', { state: { routeToDest: { lat: req.latitude, lng: req.longitude } } });
  };

  return (
    <div className="container" style={{ paddingTop: '32px' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '24px' }}>
        <h2 style={{ margin: 0, fontSize: '1.75rem', fontWeight: '800' }}>Danh sách yêu cầu</h2>
      </div>

      <div style={{ display: 'flex', gap: '12px', marginBottom: '32px', flexWrap: 'wrap' }}>
        <button onClick={() => setActiveTab('ALL')} className={`btn ${activeTab === 'ALL' ? 'btn-primary' : 'btn-outline'}`}>Tất cả</button>
        <button onClick={() => setActiveTab('MINE')} className={`btn ${activeTab === 'MINE' ? 'btn-primary' : 'btn-outline'}`}>Của tôi</button>
        <button onClick={() => setActiveTab('OTHERS')} className={`btn ${activeTab === 'OTHERS' ? 'btn-primary' : 'btn-outline'}`}>Người khác</button>

        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} style={{ padding: '8px', borderRadius: '6px', border: '1px solid #cbd5e1', marginLeft: 'auto', outline: 'none' }}>
          <option value="ALL">Mọi trạng thái</option>
          <option value="PENDING">Chờ xử lý</option>
          <option value="ASSIGNED">ASSIGNED</option>
          <option value="IN_PROGRESS">IN_PROGRESS</option>
          <option value="RESOLVED">RESOLVED</option>
        </select>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '20px' }}>
        {loading ? <p>Đang nạp dữ liệu...</p> : filtered.map(r => {
          const isMine = myRequests.some(m => m.id === r.id);
          return (
            <div 
              key={r.id} 
              onClick={() => setSelectedReq({ ...r, isMine })} 
              style={{ background: 'white', borderRadius: '12px', padding: '20px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)', cursor: 'pointer', border: '1px solid #e2e8f0', transition: 'all 0.2s ease', ':hover': { transform: 'translateY(-2px)' } }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
                <span style={{ fontWeight: 700, color: '#334155', fontSize: '1.1rem' }}>{r.requestType}</span>
                <span className={`badge ${r.status}`} style={{ fontSize: '0.75rem' }}>{r.status}</span>
              </div>
              <p style={{ color: '#64748b', fontSize: '0.95rem', marginBottom: '12px', lineHeight: '1.5' }}>
                {r.description.length > 70 ? r.description.substring(0, 70) + '...' : r.description}
              </p>
              <div style={{ fontSize: '0.85rem', color: '#94a3b8', display: 'flex', gap: '16px' }}>
                <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>👥 {r.numberOfPeople} người</span>
                <span style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>📅 {new Date(r.createdAt).toLocaleDateString()}</span>
              </div>
              {isMine && <div style={{ marginTop: '12px', fontSize: '0.75rem', fontWeight: 'bold', color: '#3b82f6' }}>YÊU CẦU CỦA BẠN</div>}
            </div>
          );
        })}
        {!loading && filtered.length === 0 && (
          <p style={{ color: '#94a3b8', fontStyle: 'italic' }}>Không tìm thấy yêu cầu nào.</p>
        )}
      </div>

      {selectedReq && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(15, 23, 42, 0.6)', backdropFilter: 'blur(4px)', display: 'flex', alignItems: 'center', justifyItems: 'center', justifyContent: 'center', zIndex: 9999 }} onClick={() => setSelectedReq(null)}>
          <div style={{ background: 'white', padding: '32px', borderRadius: '16px', width: '90%', maxWidth: '500px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }} onClick={e => e.stopPropagation()}>
            <h3 style={{ marginTop: 0, fontSize: '1.5rem', fontWeight: '800', color: '#0f172a', marginBottom: '24px' }}>Chi tiết yêu cầu</h3>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', marginBottom: '24px', fontSize: '0.95rem', color: '#334155' }}>
              <div><strong style={{ color: '#64748b' }}>Loại hỗ trợ:</strong> {selectedReq.requestType}</div>
              <div><strong style={{ color: '#64748b' }}>Trạng thái:</strong> <span className={`badge ${selectedReq.status}`}>{selectedReq.status}</span></div>
              <div><strong style={{ color: '#64748b' }}>Số lượng người:</strong> {selectedReq.numberOfPeople}</div>
              <div><strong style={{ color: '#64748b' }}>Tọa độ:</strong> {selectedReq.latitude.toFixed(4)}, {selectedReq.longitude.toFixed(4)}</div>
              <div><strong style={{ color: '#64748b' }}>Thời gian:</strong> {new Date(selectedReq.createdAt).toLocaleString()}</div>
              <div>
                <strong style={{ color: '#64748b', display: 'block', marginBottom: '4px' }}>Mô tả:</strong> 
                <p style={{ background: '#f8fafc', padding: '12px', borderRadius: '8px', margin: 0, border: '1px solid #e2e8f0' }}>{selectedReq.description}</p>
              </div>
            </div>

            <div style={{ display: 'flex', gap: '12px', marginTop: '32px' }}>
              <button className="btn btn-outline" style={{ flex: 1 }} onClick={() => setSelectedReq(null)}>Đóng</button>

              {selectedReq.isMine ? (
                 selectedReq.status === 'PENDING' && (
                   <button className="btn btn-danger" style={{ flex: 1 }} onClick={() => handleUpdateStatus(selectedReq.id, 'CANCELLED')}>Huỷ</button>
                 )
               ) : (
                 <>
                   <button className="btn btn-primary" style={{ flex: 1 }} onClick={() => handleOpenMap(selectedReq)}>Đường đi</button>
                   {currentUser.role !== 'CITIZEN' && selectedReq.status === 'PENDING' && (
                     <button className="btn btn-primary" style={{ flex: 1, backgroundColor: '#10B981', borderColor: '#10B981' }} onClick={() => handleUpdateStatus(selectedReq.id, 'ASSIGNED')}>Đến giúp</button>
                   )}
                 </>
               )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
export default RequestList;
